    final String apname = request.getParameter("ap");
    RagicBundle bundle = (RagicBundle) session.getAttribute("RAGIC_BUNDLE");
    String sheetPaths = request.getParameter("sheetPaths");
    User user = (User) session.getAttribute("USER");

    String reportString = request.getParameter("reports");
    List<Integer> reportIds = new ArrayList<>();
    if (reportString.length() > 0) {
        for (String reportStringPart : reportString.split(",")) {
            int reportId = Encoder.parseInt(reportStringPart, -1);
            if (reportId != -1) reportIds.add(reportId);
        }
    }

    Account ac = Account.getInstance(apname);
    JSONArray sheetInfos = new JSONArray(sheetPaths);

    List<Integer> selectedRootDomainIds = new ArrayList<>();
    Map<Integer, Set<Integer>> linkedFromRootDomainIds = new HashMap<>();
    final List<String> selectedNuiNames = new ArrayList<>();

    if (sheetInfos.length() + selectedRootDomainIds.size() > SELECTED_SHEET_LIMIT) {
        out.print("Selected too many sheets and reports");
        return;
    }

    for (int i = 0; i < sheetInfos.length(); i++) {
        JSONObject sheetInfo = sheetInfos.getJSONObject(i);
        String path = sheetInfo.optString("path");
        int sheetIndex = Encoder.parseInt(sheetInfo.optString("sheetIndex"), -1);
        Sheet sheet = AppManager.getSheetBySheetIndex(apname, path, sheetIndex);
        if (sheet == null) {
            out.print("No such Sheet");
            return;
        }

        NUIForm form = AppManager.getFormPage(apname, path, sheet.getFormName());
        if (form == null) form = new NUIForm(apname, path, sheet.getFormName() + "_index.nui", true);
        if (form.getNumberOfEntries() > NUM_OF_ENTRIES) {
            out.print("Too much entries");
            return;
        }


        selectedRootDomainIds.add(form.getRootDomainId());
        linkedFromRootDomainIds.put(form.getRootDomainId(), ac.getLinkedFromRootDomainIds(form));

        selectedNuiNames.add(path + "/" + form.getFileName());
        selectedNuiNames.add(path + "/" + sheetIndex + "_Sheet" + sheetIndex + "_index_t.nui");

    }

    boolean linkedCheckSuccess = true;

    for (Map.Entry<Integer, Set<Integer>> idMap : linkedFromRootDomainIds.entrySet()) {
        Integer selectedSheetId = idMap.getKey();
        Set<Integer> linkedFromIds = idMap.getValue();
        StringBuilder alertMsgBuilder = new StringBuilder();
        boolean alertMsg = false;
        for (int linkedFromId : linkedFromIds)
            if (linkedFromId < 10000 && !selectedRootDomainIds.contains(linkedFromId)) {
                if (alertMsg) alertMsgBuilder.append(",");
                linkedCheckSuccess = false;
                alertMsg = true;
                alertMsgBuilder.append(getFormRealNameByRootDomainId(apname, linkedFromId));
            }
        if (alertMsg) {
            out.println(bundle.getString("linkedNotChosenDesc").replace("{0}", getFormRealNameByRootDomainId(apname, selectedSheetId))
                    .replace("{1}", alertMsgBuilder.toString()));
        }
    }

    if (!linkedCheckSuccess) {
        return;
    }

    ReportConfig reportConfig = Account.getInstance(apname).getReportConfig();

    for(int id : reportIds) {
        boolean selectSource = false;
        Report selectedReport = reportConfig.getReport(id);
        String dataSource = selectedReport.getDataSource();
        for(String name:selectedNuiNames) {
            if(name.startsWith(dataSource)) {
                selectSource = true;
                break;
            }
        }
        if(!selectSource) {
            String[] nameParts = dataSource.split("/");
            if(nameParts.length > 2) {
                NUIForm sourceForm = AppManager.getFormPage(apname, "/" + nameParts[1], Encoder.parseInt(nameParts[2]));
                out.print(bundle.getString("reportSourceNotChosenDesc").replace("{0}", selectedReport.getName())
                        .replace("{1}", sourceForm.getRealname()));
            }
            return;
        }
    }

    Path rootPath = new File(Util.getApEnvPath(apname)).toPath();

    Files.walkFileTree(rootPath, new FileVisitor<Path>() {
        @Override
        public FileVisitResult preVisitDirectory(Path dir, BasicFileAttributes attrs) throws IOException {
            String dirName = dir.getFileName().toString();
            if (dirName.endsWith(".del") || dirName.equals("history")
                    || dirName.equals("ragic-setup") || dirName.equals("petstore")) {
                return FileVisitResult.SKIP_SUBTREE;
            } else {
                return FileVisitResult.CONTINUE;
            }
        }

        @Override
        public FileVisitResult visitFile(Path file, BasicFileAttributes attrs) throws IOException {
            String fileName = file.getFileName().toString();
            if (fileName.endsWith(".nui")) {
                String[] split = fileName.split("_");
                if(split.length > 1) {
                    int sheetIndex = Encoder.parseInt(split[0]);
                    if (sheetIndex >= 10000) return FileVisitResult.CONTINUE;

                    int pathPartLength = file.getNameCount();
                    String pathpartOfSheet;
                    if (pathPartLength > 2) {
                        pathpartOfSheet = "/" + file.getName(pathPartLength - 2) + "/" + file.getName(pathPartLength - 1);

                        if (!selectedNuiNames.contains(pathpartOfSheet)) {
                            boolean success = false;
                            int count = 1;
                            String delName = "";
                            String path = "/" + file.getName(pathPartLength - 2);
                            String realName = AppManager.getFormPage(apname, path, sheetIndex).getRealname();
                            while (!success && count < 20) {
                                delName = fileName + count + ".del";
                                Path renameToPath = Paths.get(Util.getApEnvPath(apname), file.getName(pathPartLength - 2).toString(), delName);
                                success = file.toFile().renameTo(renameToPath.toFile());
                                count++;
                            }
                            if (success) {

                                HistoryRecord r = new HistoryRecord();
                                r.setApname(apname);
                                r.setPath(path);
                                r.setPathSheet(path + "/" + sheetIndex);
                                r.setTimestamp(Instant.now().toEpochMilli());
                                r.setUserId(user.getUserId());
                                r.setUserName(user.getUserName(apname));
                                r.setDelFileName(delName);
                                r.setMenuType("sheet");
                                String pathName = "";
                                App ins = Account.getInstance(apname).getApp(path);
                                if (ins != null) {
                                    pathName = ins.getApplicationName();
                                }

                                String content = Encoder.encjs(user.getUserIdText(apname)) + bundle.getString("space") +
                                        "<b>" + bundle.getString("removed") + bundle.getString("space") +
                                        bundle.getString("sheet") + ": " + "[" + Encoder.encjs(pathName) + "] " + Encoder.encjs(realName) + "</b>";
                                r.setContent(content);
                                r.store();
                                Account.getInstance(apname).logRemoveForm(r, String.valueOf(sheetIndex), realName, bundle);
                                AppManager.removeFormFromConfig(apname, path, String.valueOf(sheetIndex));
                                MenuConfiguration mc = Account.getInstance(apname).getMenuConfiguration();
                                mc.removeSheet(path, sheetIndex);
                            }
                        }
                    }
                }
            }
            return FileVisitResult.CONTINUE;
        }

        @Override
        public FileVisitResult visitFileFailed(Path file, IOException exc) throws IOException {
            return FileVisitResult.CONTINUE;
        }

        @Override
        public FileVisitResult postVisitDirectory(Path dir, IOException exc) throws IOException {
            return FileVisitResult.CONTINUE;
        }
    });

    for(Report report :reportConfig.listNonTemplateReports()) {
        if(!reportIds.contains(report.getId())) {
            reportConfig.deleteReport(report.getId(), null);
        }
    }

    reportConfig.save(user);

    AccountPaymentStatus aps = ac.getPaymentStatus(true);
    ac.resetCompanySetting(bundle);
    ac.resetFeatureSetting(bundle);

    TemplateHelper th_en = new TemplateHelper(apname,  Const.BUNDLE_EN);
    TemplateHelper th_tw = new TemplateHelper(apname,  Const.BUNDLE_ZHTW);

    for(String installedId : th_en.getAllInstalledIds()) {
        th_en.getTemplate(installedId).install(user);
    }

    for(String installedId : th_tw.getAllInstalledIds()) {
        th_tw.getTemplate(installedId).install(user);
    }

    NUIFormSetInfo.resetForms(apname, session);
    aps.modifyPlan("FREE2");
    Account.removeInstance(apname);

    out.print(bundle.getString("accountDowngradeSuccess").replace("{0}", com.ragic.s3.util.Util.getServerUrl(RagicConfig.getInstance()) + "/" + apname));





